const source = $('Refund Form Webhook').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? $input.first()?.json ?? {};
const query = source.query ?? source;
const settings = $('Load Global Settings').first()?.json ?? {};
const headers = source.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const actionUrl = `${n8nBaseUrl}/webhook/add-refund`;
const previewUrl = `${n8nBaseUrl}/webhook/preview-refund-request-email`;
const statusFormUrl = `${n8nBaseUrl}/webhook/refund-status-form`;
const name = clean(query.name);
const refundFor = clean(query.refund_for ?? query.for_name ?? query.for);
const reason = clean(query.reason);
const membership = clean(query.membership);
const amount = clean(query.amount);
const fromDate = clean(query.from_date ?? query.fromDate);
const toDate = clean(query.to_date ?? query.toDate);
const status = clean(query.status) || 'Request Bank Details';
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Refund Form</title>
  <style>
    :root { color-scheme: light; --bg: #f7f8fc; --panel: #ffffff; --ink: #243447; --muted: #66788a; --line: #d9e2ec; --accent: #2f80d8; --accent-dark: #2567ad; }
    * { box-sizing: border-box; }
    body { margin: 0; padding: 24px; min-height: 100vh; font-family: Lato, 'Helvetica Neue', Arial, sans-serif; background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%); color: var(--ink); }
    .wrap { max-width: 760px; margin: 0 auto; background: var(--panel); border: 1px solid var(--line); border-radius: 18px; padding: 28px; box-shadow: 0 18px 40px rgba(36, 52, 71, 0.08); }
    h1 { margin: 0 0 10px; font-size: 32px; line-height: 1.1; }
    p { margin: 0 0 20px; color: var(--muted); }
    form { display: grid; gap: 16px; }
    .grid { display: grid; gap: 16px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }
    label { display: block; font-weight: 700; margin-bottom: 6px; }
    input { width: 100%; border: 1px solid var(--line); border-radius: 10px; padding: 10px 12px; font: inherit; color: var(--ink); background: #fff; }
    .actions { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
    button, .close-button { appearance: none; border: 0; border-radius: 999px; padding: 12px 18px; font: inherit; font-weight: 700; cursor: pointer; text-decoration: none; }
    button { color: #fff; background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dark) 100%); }
    .close-button { color: var(--ink); background: #eef2f7; border: 1px solid var(--line); }
    .note { font-size: 14px; color: var(--muted); }
  </style>
</head>
<body>
  <div class="wrap">
    <h1>Refund Form</h1>
    <p>Create a refund row. The webhook calculates <code>months</code>, <code>refund</code>, and <code>explanation</code> from the dates and amount.</p>
    <form action="${actionUrl}" method="get" target="_blank">
      <input type="hidden" name="created_by" value="refund_form_webhook">
      <div class="grid">
        <div>
          <label for="name">Name</label>
          <input id="name" name="name" type="text" value="${escapeHtml(name)}" required>
        </div>
        <div>
          <label for="refund_for">For</label>
          <input id="refund_for" name="refund_for" type="text" value="${escapeHtml(refundFor)}" required>
        </div>
      </div>
      <div class="grid">
        <div>
          <label for="reason">Reason</label>
          <input id="reason" name="reason" type="text" list="reason-options" value="${escapeHtml(reason)}" required>
          <datalist id="reason-options">
            <option value="Injured"></option>
            <option value="Deceased"></option>
          </datalist>
        </div>
        <div>
          <label for="membership">Membership</label>
          <input id="membership" name="membership" type="text" value="${escapeHtml(membership)}" required>
        </div>
      </div>
      <div class="grid">
        <div>
          <label for="amount">Amount</label>
          <input id="amount" name="amount" type="number" min="0" step="0.01" value="${escapeHtml(amount)}" required>
        </div>
        <div>
          <label for="status">Status</label>
          <input id="status" name="status" type="text" value="${escapeHtml(status)}" required>
        </div>
      </div>
      <div class="grid">
        <div>
          <label for="from_date">From Date</label>
          <input id="from_date" name="from_date" type="date" value="${escapeHtml(fromDate)}" required>
        </div>
        <div>
          <label for="to_date">To Date</label>
          <input id="to_date" name="to_date" type="date" value="${escapeHtml(toDate)}" required>
        </div>
      </div>
      <div class="actions">
        <button type="submit">Create Refund</button>
        <button type="submit" formaction="${previewUrl}">Send Request</button>
        <button type="button" class="close-button" onclick="window.close()">Close</button>
        <span class="note">Suggested reasons are provided, but you can type your own. The send request flow opens a preview before you send the treasury email.</span>
      </div>
    </form>
  </div>
</body>
</html>`;
return [{ json: { html } }];
